const body = request.body || {};
const keyString = body.clave || "";
const encryptedText = body.texto || "";

if (!keyString || !encryptedText) {
  $_EXCEPTION_("Los campos 'clave' y 'texto' son obligatorios", null, 400);
}

try {
  const parts = encryptedText.split(':');
  if (parts.length !== 2) {
    $_EXCEPTION_("El formato del texto encriptado es invalido. Formato esperado: 'iv_hex:encrypted_base64'", null, 400);
  }

  const ivHex = parts[0];
  const encryptedData = parts[1];

  // Using Buffer to handle hex strings properly
  let iv;
  if (typeof Buffer !== 'undefined') {
    iv = Buffer.from(ivHex, 'hex');
  } else {
    iv = new Uint8Array(ivHex.match(/.{1,2}/g).map(byte => parseInt(byte, 16)));
  }

  const key = crypto.createHash('sha256').update(String(keyString)).digest();
  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);

  let decrypted = decipher.update(encryptedData, 'base64', 'utf8');
  decrypted += decipher.final('utf8');

  $_RETURN_DATA_ = { decrypted: decrypted };
} catch (e) {
  $_EXCEPTION_("Error al desencriptar. Clave incorrecta o formato invalido.", { error: e.message }, 400);
}
